class Solution {
    public int[][] validArrangement(int[][] pairs) {
        Map<Integer, List<Integer>> graph = new HashMap<>();
        Map<Integer, Integer> outDegree = new HashMap<>();

        for (int[] pair : pairs) {
            int start = pair[0], end = pair[1];
            graph.computeIfAbsent(start, k -> new ArrayList<>()).add(end);
            outDegree.put(start, outDegree.getOrDefault(start, 0) + 1);
            outDegree.put(end, outDegree.getOrDefault(end, 0) - 1);
        }

        int startNode = -1;
        for (int[] pair : pairs) {
            if (outDegree.get(pair[0]) == 1) {
                startNode = pair[0];
                break;
            }
        }

        List<int[]> result = new ArrayList<>();
        dfs(graph, startNode, result);
        Collections.reverse(result);
        return result.toArray(new int[0][]);
    }

    private void dfs(Map<Integer, List<Integer>> graph, int node, List<int[]> result) {
        while (graph.get(node) != null && !graph.get(node).isEmpty()) {
            int nextNode = graph.get(node).remove(0);
            dfs(graph, nextNode, result);
        }
        result.add(new int[] {node, outDegree.get(node) + 1});
    }
}
